module multi_pipe_4bit
#(
    parameter size = 4
)
(
    input clk,
    input rst_n,
    input mul_a,
    input mul_b,
    output reg mul_out
);
parameter size = 4;
reg [size-1:0] extension_a;
reg [size-1:0] extension_b;
reg [size-1:0] partial_product [0:size-1];
reg [size-1:0] sum [0:size-1];
integer i;
always @(*) begin
    for (i = 0; i < size; i = i + 1) begin
        if (mul_b[i] == 1'b1) begin
            partial_product[i] = {size{1'b0}} + (mul_a << i);
        end
        else begin
            partial_product[i] = 'd0;
        end
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        for (i = 0; i < size; i = i + 1) begin
            sum[i] <= 'd0;
        end
    end
    else begin
        for (i = 0; i < size; i = i + 1) begin
            sum[i] <= partial_product[i][size-1:0] + sum[i][size-1:0];
        end
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out <= 'd0;
    end
    else begin
        mul_out <= sum[0] + (sum[1] << 1) + (sum[2] << 2) + (sum[3] << 3);
    end
end
endmodule
